member.example:
Bind the CanvasGroup alpha property using a serialized binder field — the target CanvasGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CanvasGroupAlphaBinder _alpha;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _alpha;
    }


Bind the CanvasGroup alpha property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CanvasGroup _canvasGroup;
        
        private CanvasGroupAlphaBinder Alpha =>
            new(_canvasGroup);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _alpha;
    }

Switch the CanvasGroup alpha between two values using a serialized binder field — the target CanvasGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CanvasGroupAlphaSwitcherBinder _isVisible;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }


Switch the CanvasGroup alpha between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CanvasGroup _canvasGroup;
        
        private CanvasGroupAlphaSwitcherBinder IsVisible => new(
            _canvasGroup, trueValue: 1f, falseValue: 0f);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }
